INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Relance commerciale et recherche de nouveaux marchés', 'Formation sur les techniques de relance commerciale et la conquête de nouveaux marchés.', 5, 250000.00, 'entreprise', '2026-11-05', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Maîtriser les techniques de relance commerciale\n• Identifier et exploiter de nouveaux marchés\n• Développer des stratégies de prospection et fidélisation\n• Utiliser les outils digitaux et CRM pour suivre clients et prospects\n• Optimiser la performance commerciale avec une approche proactive\n\n--- OBJECTIFS DÉTAILLÉS ---\nMaîtriser les techniques de relance commerciale, identifier et exploiter de nouveaux marchés, développer des stratégies de prospection et fidélisation, utiliser les outils digitaux et CRM et optimiser la performance commerciale.\n\n--- PRÉREQUIS ---\nExpérience préalable en vente ou relation client souhaitée.\n\n--- CONTENU ---\nModule 1 : Introduction à la relance commerciale et à la conquête de nouveaux marchés\nModule 2 : Préparation à la relance commerciale\nModule 3 : Techniques de relance et de communication\nModule 4 : Prospection et recherche de nouveaux marchés\nModule 5 : Stratégies de fidélisation et relance combinées\nModule 6 : Utilisation des outils numériques et CRM\nModule 7 : Atelier final – Plan d’action commercial\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nCommerciaux, chargés de clientèle, responsables marketing et commerciaux, chefs d’équipe.\n\n--- MÉTHODES ---\nPrésentations interactives, études de cas, mises en situation, ateliers pratiques, jeux de rôle et exercices d’analyse de marché.\n\n--- SUPPORTS ---\nCRM, outils digitaux de prospection, scripts de relance, modèles de suivi client, supports PDF et slides.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
